%% 侧风扰动 vs 无风对比仿真\nload('plan.mat');\n\n%% 仿真1: 有侧风 (W_g = [0;0;1] 即 1m/s右侧风)\nW_g = [0; 0; 1]; assignin('base','W_g',W_g);\nout_wind = sim('planmodel.slx', 'StopTime', '200');\nfprintf('有侧风仿真完成\n');\n\n%% 仿真2: 无风\nW_g = [0; 0; 0]; assignin('base','W_g',W_g);\nout_nowind = sim('planmodel.slx', 'StopTime', '200');\nfprintf('无风仿真完成\n');\n\n%% 提取时间\nt = out_wind.tout;\n\n%% 从 logsout 提取信号\nls_w = out_wind.logsout;\nls_n = out_nowind.logsout;\n\n%% 用信号索引号 - 先看看有哪些信号\nnum_sigs = ls_w.numElements();\nfprintf('共 %d 个信号\n', num_sigs);\n\n%% 创建图形窗口对比\nfigure('Position', [100 100 1600 1000]);\n\n%% 遍历一些关键信号\nfor sig_idx = 1:min(20, num_sigs)\n    el_w = ls_w.getElement(sig_idx);\n    el_n = ls_n.getElement(sig_idx);\n    val_w = el_w.Values;\n    val_n = el_n.Values;\n    \n    d_w = val_w.Data;\n    d_n = val_n.Data;\n    \n    fprintf('信号[%d]: 有风 max=%.3f min=%.3f, 无风 max=%.3f min=%.3f\n', ...\n        sig_idx, max(d_w(:)), min(d_w(:)), max(d_n(:)), min(d_n(:)));\nend\n